import articles from '../fixtures'
import {DELETE_ARTICLE, FILTER_ARTICLES} from '../types'

export default function (initialState = articles, action) {
    switch (action.type) {
        case DELETE_ARTICLE:
            return initialState.filter(article => article.id !== action.payload.id)
        case FILTER_ARTICLES:
            return initialState.filter(article => article.id === action.payload.id)
        default:
            return initialState
    }
}
